    "id": "s4087",
    "type": "series",
    "title": "The X-Files",
    "year": "1993–2018",
    "firstAirDate": "1993-09-10",
    "lastAirDate": "2018-03-21",
    "rating": "8.4",
    "imdbRating": "8.4",
